TOPICS_DATA["github-actions"]["github-actions-workflow"] = {"id":"github-actions-workflow","title":"Workflow","difficulty":"beginner","estimatedMinutes":15,"tldr":["A GitHub Actions workflow is an automated process defined in YAML that runs on GitHub Actions runners.","Workflows are stored in .github/workflows/ as .yml files. Each workflow can contain multiple jobs.","Workflows are triggered by events (push, PR, schedule) and consist of jobs that run steps.","Workflow works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"A workflow is like a recipe card that tells GitHub what to do when something happens in your repo. \"When someone pushes to main, run tests, build the app, and deploy it.\" The recipe is written in a YAML file and lives in your repository under .github/workflows/.","deepDive":[{"heading":"Workflow Structure","text":"name: display name for workflow. on: events that trigger the workflow. jobs: collection of jobs to run. Each job: runs-on (runner type), steps (actions/commands), needs (dependencies), if (conditions). env: environment variables. defaults: default settings for all jobs."},{"heading":"Workflow Anatomy","text":"A workflow can have multiple jobs. Jobs run in parallel by default, or sequentially using needs. Each job has multiple steps. Steps can be: shell commands (run:) or actions (uses:). Steps share data via environment variables and filesystem. Workflows can be triggered by multiple events."},{"heading":"Common Use Cases","text":"Workflow applies to build automation, continuous integration, test execution, deployment orchestration, and infrastructure management. Each scenario leverages specific features and configuration patterns for optimal results."}],"interviewAnswer":"A GitHub Actions workflow is an automated process defined in YAML that runs on GitHub Actions runners.","interviewQuestions":[{"question":"What is a GitHub Actions workflow?","answer":"An automated process defined in a YAML file in .github/workflows/ that runs on GitHub Actions runners."},{"question":"Where are workflow files stored?","answer":"In the .github/workflows/ directory as .yml files."},{"question":"Can a workflow have multiple jobs?","answer":"Yes. Jobs run in parallel by default or sequentially using the needs keyword."},{"question":"Workflow — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Workflow — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Workflow — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Workflow — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Workflow — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Workflow — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Workflow — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Workflow</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">.github/workflows</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">YAML files</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Workflow</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated process</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Jobs</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Parallel tasks</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Steps</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Actions/commands</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Workflow: Automated process in .github/workflows/*</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">.yml. Triggered by events. Contains jobs with step</text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">s.</text></svg>","codeExamples":[{"title":"Basic Workflow","useCase":"Minimal workflow YAML.","code":"name: CI\non: [push]\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - run: echo \"Hello!\"","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"Where are GitHub Actions workflows stored?","options":["src/workflows/",".github/workflows/","actions/","workflows/"],"answer":1,"explanation":"Workflow files must be in .github/workflows/ directory."},{"question":"Workflow — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Workflow — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Workflow — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Workflow — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Workflow — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Workflow — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Workflow — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Workflow — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Workflow — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-yaml"] = {"id":"github-actions-yaml","title":"Workflow YAML Syntax","difficulty":"intermediate","estimatedMinutes":20,"tldr":["GitHub Actions workflows use YAML (YAML Ain't Markup Language) for configuration — a human-readable data serialization format.","Key YAML concepts: indentation (spaces, not tabs), key-value pairs, lists, nested objects, multi-line strings.","Actions YAML uses specific keywords: name, on, jobs, runs-on, steps, uses, run, with, env, if, needs.","Workflow YAML Syntax works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Workflow YAML is like filling out a structured form for GitHub. Every line has meaning: indentation shows hierarchy, dashes start lists, colons separate keys from values. Getting indentation wrong is the most common mistake — YAML uses spaces, never tabs.","deepDive":[{"heading":"YAML Basics","text":"Scalars: strings (with/without quotes), numbers, booleans. Lists (arrays): items start with dash and space. Dictionaries (objects): key: value pairs. Nested: indent with 2 spaces. Multi-line: | (literal block) or > (folded block). Comments: #. Anchors: & and * for reusing values."},{"heading":"Workflow Keywords","text":"name: workflow display name. run-name: workflow run name (dynamic). on: trigger events. env: global environment variables. defaults: default settings. concurrency: cancel/queue control. permissions: job permissions. jobs: map of job IDs. timeout-minutes: max run time."},{"heading":"Common Pitfalls","text":"Tabs vs spaces (always use spaces). Wrong indentation level. Missing colons. Incorrect boolean values (true/false lowercase in some contexts). Special characters in strings (quote them). Mismatched quotes. Overly long lines."}],"interviewAnswer":"GitHub Actions workflows use YAML (YAML Ain't Markup Language) for configuration — a human-readable data serialization format.","interviewQuestions":[{"question":"What is YAML?","answer":"A human-readable data serialization format used for GitHub Actions workflow configuration."},{"question":"What is the most common YAML mistake?","answer":"Using tabs instead of spaces for indentation. YAML requires spaces."},{"question":"How to write a multi-line string in YAML?","answer":"Use | (literal block, preserves newlines) or > (folded block, wraps lines)."},{"question":"Workflow YAML Syntax — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Workflow YAML Syntax — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Workflow YAML Syntax — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Workflow YAML Syntax — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Workflow YAML Syntax — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Workflow YAML Syntax — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Workflow YAML Syntax — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Workflow YAML Syntax</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">name: CI</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Workflow name</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">on: [push]</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Trigger event</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">jobs:</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job definitions</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">  build:</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job ID</text><rect x=\"10\" y=\"155\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"80\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">    steps:</text><text x=\"80\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Step list</text><text x=\"240\" y=\"190\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">YAML: Indentation-based format. Spaces only. Synta</text><text x=\"240\" y=\"202\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">x: name, on, jobs, steps. Most common error: tabs </text><text x=\"240\" y=\"214\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">instead of spaces.</text></svg>","codeExamples":[{"title":"YAML Example","useCase":"Workflow with common syntax.","code":"name: Deploy\non:\n  push:\n    branches: [main]\njobs:\n  deploy:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - run: npm ci && npm run build","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What indentation is used in YAML?","options":["Tabs","Spaces (usually 2)","4 spaces only","No indentation"],"answer":1,"explanation":"YAML uses spaces for indentation (traditionally 2 spaces). Tabs are NOT allowed."},{"question":"Workflow YAML Syntax — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Workflow YAML Syntax — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Workflow YAML Syntax — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Workflow YAML Syntax — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Workflow YAML Syntax — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Workflow YAML Syntax — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Workflow YAML Syntax — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Workflow YAML Syntax — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Workflow YAML Syntax — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-events"] = {"id":"github-actions-events","title":"Events","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Events are activities in a repository that trigger workflow runs. Workflows listen for events using the \"on\" keyword.","Event types: webhook events (push, pull_request), scheduled (cron), manual (workflow_dispatch), and external (repository_dispatch).","Events carry payload data (github.event context) accessible in workflow steps.","Events works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Events are the triggers that start your workflow — like pressing a button. Push = \"someone pushed code.\" Pull Request = \"someone opened a PR.\" Schedule = \"it's 3 AM.\" You can also manually trigger (workflow_dispatch) or let an external system trigger via API (repository_dispatch).","deepDive":[{"heading":"Webhook Events","text":"push: code pushed. pull_request: PR opened/synchronized/reopened. release: release published. issues: issue opened/closed. discussion: discussion created. workflow_run: another workflow completed. page_build: GitHub Pages build. deployment: deployment created. Many more: 50+ event types."},{"heading":"Event Filters","text":"Branches: branches: [main, develop]. Tags: tags: [v*]. Paths: paths: [src/**, tests/**]. Activity types: types: [opened, synchronize, closed]. File types: paths-ignore: [*.md, docs/**]. Scheduled: cron syntax (5 fields). Workflow dispatch: manual with inputs."},{"heading":"Event Payload","text":"github.event object contains event data. github.event_name: event type string. github.ref: branch/tag ref. github.sha: commit SHA. github.actor: who triggered. GitHub context (${{ github }}) vs event context (${{ github.event }}). Payload varies by event type."}],"interviewAnswer":"Events are activities in a repository that trigger workflow runs. Workflows listen for events using the \"on\" keyword.","interviewQuestions":[{"question":"What is a workflow event?","answer":"An activity in a repository that triggers a workflow run, defined using the on keyword."},{"question":"How to trigger workflow on specific branch only?","answer":"Use branch filter: on: push: branches: [main]."},{"question":"What event allows manual workflow triggers?","answer":"workflow_dispatch — adds a \"Run workflow\" button in the GitHub UI."},{"question":"Events — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Events — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Events — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Events — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Events — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Events — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Events — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Events</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code pushed</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pull Request</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PR opened/synced</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Schedule</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cron timer</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Workflow Dispatch</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Manual button</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Events: Activities that trigger workflows. Push, P</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">R, schedule, manual, release, issues, and more.</text></svg>","codeExamples":[{"title":"Event Examples","useCase":"Different event triggers.","code":"on: [push, pull_request]\non:\n  schedule:\n    - cron: \"0 2 * * *\"\n  workflow_dispatch:\n    inputs:\n      environment:\n        type: choice\n        options: [dev, staging, prod]","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What cron expression runs a workflow daily at midnight?","options":["0 0 * * *","0 12 * * *","*/5 * * *","0 0 1 * *"],"answer":0,"explanation":"\"0 0 * * *\" means minute 0, hour 0 (midnight), every day, every month, every day of week."},{"question":"Events — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Events — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Events — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Events — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Events — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Events — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Events — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Events — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Events — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-triggers"] = {"id":"github-actions-triggers","title":"Triggers","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Triggers define WHEN a workflow runs. They are event types optionally combined with activity type, branch, path, and tag filters.","A single workflow can have multiple triggers. If ANY trigger event occurs and passes its filters, the workflow runs.","Triggers can be combined with concurrency controls to manage workflow run behavior.","Triggers works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Triggers are the conditions that start your workflow. \"Run when: someone pushes to main, OR a PR is opened against develop, OR it's 3 AM on weekdays.\" You can mix and match triggers, and each trigger can have its own filters (only run for specific branches or file paths).","deepDive":[{"heading":"Trigger Types","text":"Single event: on: push. Multiple events: on: [push, pull_request]. Event with activity: on: pull_request: types: [opened]. Event with filters: on: push: branches: [main] tags: [v*]. Multiple events with filters: use array or nested syntax."},{"heading":"Path Filtering","text":"paths: [src/**] — only run when files in src/ change. paths-ignore: [*.md] — skip when only markdown changes. Path filters affect only push and pull_request events. Useful for monorepos to run only relevant workflows. Supports glob patterns."},{"heading":"Concurrency","text":"concurrency: group name for workflow runs. cancel-in-progress: true — cancel previous runs. Useful for: deploy workflows (only latest deploy runs), CI (cancel old commits). Group by branch or environment."}],"interviewAnswer":"Triggers define WHEN a workflow runs. They are event types optionally combined with activity type, branch, path, and tag filters.","interviewQuestions":[{"question":"How to trigger workflow on multiple events?","answer":"Use array syntax: on: [push, pull_request, workflow_dispatch]."},{"question":"What does paths-ignore do?","answer":"Skips workflow execution when changes only match the ignored paths (e.g., documentation-only changes)."},{"question":"What does cancel-in-progress do?","answer":"Automatically cancels any currently running workflow in the same concurrency group before starting a new one."},{"question":"Triggers — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Triggers — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Triggers — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Triggers — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Triggers — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Triggers — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Triggers — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Triggers</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Event</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Push, PR, schedule</text><line x1=\"120\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"205\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Filters</text><text x=\"205\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Branch, path, tag</text><line x1=\"260\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"290\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"345\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Run?</text><text x=\"345\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Yes or No</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Triggers: Events + optional filters (branch, path,</text><text x=\"240\" y=\"122\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> tag). Multiple triggers can be combined. Concurre</text><text x=\"240\" y=\"134\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ncy controls available.</text></svg>","codeExamples":[{"title":"Multiple Triggers","useCase":"Workflow with event + filters.","code":"on:\n  push:\n    branches: [main]\n    paths: [src/**]\n  pull_request:\n    branches: [develop]\n  workflow_dispatch:","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the purpose of concurrency in workflows?","options":["Run more jobs","Control workflow execution, cancel duplicates","Increase parallelism","Reduce costs"],"answer":1,"explanation":"Concurrency controls workflow execution, often used to cancel in-progress runs when a new one starts (e.g., cancel old CI on new push)."},{"question":"Triggers — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Triggers — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Triggers — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Triggers — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Triggers — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Triggers — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Triggers — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Triggers — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Triggers — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-jobs"] = {"id":"github-actions-jobs","title":"Jobs","difficulty":"intermediate","estimatedMinutes":15,"tldr":["A job is a unit of work in a workflow that runs on a single runner. Each job consists of multiple steps.","Jobs run in parallel by default. Use the needs keyword to create sequential dependencies between jobs.","Key job properties: runs-on, steps, needs, if (condition), strategy (matrix), container, services, env, timeout-minutes.","Jobs works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"A job is like a single task in your workflow. \"Build the app\" is one job. \"Run tests\" is another job. \"Deploy\" is a third job. They can run at the same time (parallel) or one after another (sequential). Each job runs on its own virtual machine (runner).","deepDive":[{"heading":"Job Properties","text":"runs-on: runner type (ubuntu-latest, windows-latest, self-hosted). needs: list of jobs that must complete before this one starts. if: condition to skip/run the job. strategy: matrix configuration. container: run job in a container. services: service containers (DB, Redis). env: job-level environment variables. timeout-minutes: max job duration."},{"heading":"Job Dependencies","text":"Parallel: jobs with no needs run simultaneously. Sequential: job A needs job B (A waits for B). Dependency graph: A needs [B, C] (A waits for B and C). Multiple levels: C needs B, B needs A. DAG: directed acyclic graph — no circular dependencies."},{"heading":"Job Outputs","text":"Outputs: job outputs accessible by dependent jobs. Set: echo \"::set-output name=key::value\" (deprecated) or echo \"key=value\" >> $GITHUB_OUTPUT. Access: ${{ needs.build.outputs.key }}. Outputs are strings. Can pass files via artifacts."}],"interviewAnswer":"A job is a unit of work in a workflow that runs on a single runner. Each job consists of multiple steps.","interviewQuestions":[{"question":"What is a job in GitHub Actions?","answer":"A unit of work that runs on a single runner, consisting of multiple steps."},{"question":"How to make jobs run sequentially?","answer":"Use needs keyword: job2: needs: [job1]."},{"question":"What is the default job execution order?","answer":"Jobs without needs run in parallel. Jobs with needs wait for their dependencies."},{"question":"Jobs — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Jobs — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Jobs — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Jobs — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Jobs — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Jobs — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Jobs — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Jobs</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job A: Build</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Runs first (no needs)</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job B: Test</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Parallel (no needs)</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job C: Deploy</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Needs: [A, B]</text><text x=\"240\" y=\"140\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Jobs: Units of work on a single runner. Parallel b</text><text x=\"240\" y=\"152\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">y default. Sequential via needs. Properties: runs-</text><text x=\"240\" y=\"164\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">on, steps, needs, if, strategy.</text></svg>","codeExamples":[{"title":"Job Dependencies","useCase":"Parallel + sequential jobs.","code":"jobs:\n  build:\n    steps: [run: npm ci && npm run build]\n  test:\n    needs: [build]\n    steps: [run: npm test]\n  deploy:\n    needs: [test]\n    steps: [run: npm run deploy]","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the default execution mode for jobs without needs?","options":["Sequential","Parallel","Random","Manual"],"answer":1,"explanation":"Jobs without needs run in parallel simultaneously. Jobs with needs wait for their dependencies."},{"question":"Jobs — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Jobs — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Jobs — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Jobs — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Jobs — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Jobs — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Jobs — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Jobs — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Jobs — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-steps"] = {"id":"github-actions-steps","title":"Steps","difficulty":"beginner","estimatedMinutes":10,"tldr":["Steps are individual tasks within a job. Each step runs in the same runner (shares the filesystem).","Steps can be: shell commands (run:) or pre-built actions (uses:).","Steps can access outputs of previous steps, set outputs, and have conditions (if).","Steps works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Steps are the individual instructions in your job. \"Check out the code\" is a step. \"Install dependencies\" is a step. \"Run tests\" is a step. Steps are like items on a to-do list — they run in order, one after another, in the same environment.","deepDive":[{"heading":"Step Types","text":"run: execute shell commands directly in the runner. uses: use a pre-built action (from Marketplace or local repo). Uses format: owner/repo@ref (actions/checkout@v4). name: optional display name. id: step identifier for referencing outputs. working-directory: set working dir for run steps."},{"heading":"Step Properties","text":"if: condition to run step (e.g., if: failure(), if: success(), if: always()). env: step-level environment variables. continue-on-error: true — step failure doesn\\'t fail the job. timeout-minutes: step timeout. shell: override shell (bash, pwsh, python, node)."},{"heading":"Step Outputs","text":"Set: echo \"{key}={value}\" >> $GITHUB_OUTPUT. Access: ${{ steps.step_id.outputs.key }}. Steps share filesystem but not environment by default (use export or GITHUB_ENV)."}],"interviewAnswer":"Steps are individual tasks within a job. Each step runs in the same runner (shares the filesystem).","interviewQuestions":[{"question":"What is a step in GitHub Actions?","answer":"An individual task in a job — either a shell command (run) or a pre-built action (uses)."},{"question":"How to make a step conditional?","answer":"Use the if property: if: github.ref == \\'refs/heads/main\\'."},{"question":"How do steps share data?","answer":"Via the filesystem (same working directory), step outputs ($GITHUB_OUTPUT), or environment files ($GITHUB_ENV)."},{"question":"Steps — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Steps — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Steps — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Steps — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Steps — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Steps — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Steps — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Steps</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 1: Checkout</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">actions/checkout@v4</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 2: Install</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm ci</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 3: Test</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm test</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 4: Deploy</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy action</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Steps: Individual tasks in a job. run: for command</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">s, uses: for actions. Share filesystem. Run sequen</text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">tially.</text></svg>","codeExamples":[{"title":"Step Examples","useCase":"Different step types.","code":"steps:\n  - name: Checkout code\n    uses: actions/checkout@v4\n  - name: Install deps\n    run: npm ci\n  - name: Conditional step\n    if: github.ref == 'refs/heads/main'\n    run: echo \"Deploying...\"","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does the continue-on-error property do?","options":["Stops the job","Continues job even if step fails","Retries the step","Skips the step"],"answer":1,"explanation":"continue-on-error: true allows the job to continue even if this step fails (marks as warning)."},{"question":"Steps — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Steps — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Steps — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Steps — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Steps — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Steps — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Steps — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Steps — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Steps — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-runners"] = {"id":"github-actions-runners","title":"Runners","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Runners are the virtual machines or containers that execute GitHub Actions jobs.","GitHub-hosted runners: Ubuntu, Windows, macOS provided by GitHub (free minutes, then pay-as-you-go).","Runners are selected using the runs-on keyword in job definitions.","Runners works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"A runner is the computer that runs your workflow. When a workflow triggers, GitHub spins up a fresh virtual machine (runner), runs your jobs on it, and then destroys it. You can use GitHub's computers (GitHub-hosted) or your own (self-hosted).","deepDive":[{"heading":"GitHub-Hosted Runners","text":"Ubuntu: ubuntu-latest (22.04), ubuntu-24.04, ubuntu-22.04, ubuntu-20.04. Windows: windows-latest (2022), windows-2022, windows-2019. macOS: macos-latest (14), macos-14, macos-13. Each has pre-installed software (Node, Python, Docker, etc.). 2-core CPU, 7GB RAM default (larger sizes available)."},{"heading":"Runner Sizing","text":"Standard: 2-core, 7GB RAM, 14GB SSD. Large (paid): 4-core/16GB, 8-core/32GB, 16-core/64GB. Use larger runners for: resource-intensive builds, Docker builds, parallel test execution. Pricing: per-minute for larger runners (Linux ~$0.008/min for 4-core)."},{"heading":"Runner Selection","text":"runs-on: ubuntu-latest (always latest version). runs-on: [self-hosted, linux, x64, gpu] (label matching for self-hosted). Label groups: OS labels, architecture labels, custom labels. Runner can be selected by multiple labels."}],"interviewAnswer":"Runners are the virtual machines or containers that execute GitHub Actions jobs.","interviewQuestions":[{"question":"What is a GitHub Actions runner?","answer":"A virtual machine that executes workflow jobs. GitHub-hosted (managed) or self-hosted (your infrastructure)."},{"question":"What OS options are available for GitHub-hosted runners?","answer":"Ubuntu Linux, Windows Server, macOS."},{"question":"How to select a specific runner size?","answer":"Runs on standard by default. Use runs-on: ubuntu-latest-4core for larger sizes (paid plans)."},{"question":"Runners — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Runners — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Runners — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Runners — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Runners — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Runners — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Runners — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Runners</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Ubuntu</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Linux runner</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Windows</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Windows runner</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">macOS</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Mac runner</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Self-Hosted</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Your hardware</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Runners: VMs executing jobs. GitHub-hosted (Ubuntu</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">, Windows, macOS) or self-hosted. Selected via run</text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">s-on.</text></svg>","codeExamples":[{"title":"Runner Selection","useCase":"Choose runner types.","code":"jobs:\n  build:\n    runs-on: ubuntu-latest\n  test-win:\n    runs-on: windows-latest\n  deploy:\n    runs-on: [self-hosted, production]","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does runs-on: ubuntu-latest select?","options":["Latest Ubuntu version available","Ubuntu 20.04","A specific commit","Any Linux"],"answer":0,"explanation":"ubuntu-latest points to the latest stable Ubuntu version provided by GitHub Actions."},{"question":"Runners — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Runners — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Runners — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Runners — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Runners — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Runners — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Runners — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Runners — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Runners — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-self-hosted"] = {"id":"github-actions-self-hosted","title":"Self-Hosted Runner","difficulty":"advanced","estimatedMinutes":20,"tldr":["Self-hosted runners are runners you install and manage on your own infrastructure (on-premise or cloud VMs).","Benefits: more control (OS, hardware, software), access to internal resources, cost-effective for high usage.","Considerations: security (runners execute arbitrary code), maintenance (updates, patching), scaling.","Self-Hosted Runner works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"A self-hosted runner is like having your own computer dedicated to running workflows. Instead of waiting for GitHub's machines, you use your own. This gives you full control over what software is installed, how powerful the machine is, and what networks it can access.","deepDive":[{"heading":"Setup Process","text":"Go to Settings > Actions > Runners > Add runner. Download and run the configure script on your machine. OS: Linux, Windows, macOS. Architecture: x64, ARM64. One runner per machine (but can run multiple runner services). Register with token."},{"heading":"Security Considerations","text":"Pubic repositories: anyone can fork your repo and run workflows on your runner (dangerous!). Use only with private repos or add appropriate restrictions. Runner isolation: each job should run in clean environment (use ephemeral runners). No sensitive data in open source repos with self-hosted runners."},{"heading":"Scaling","text":"Elastic scaling: auto-scale runner count based on job queue. Tools: actions-runner-controller (Kubernetes), terraform-aws-github-runner (AWS). Ephemeral runners: one job per runner, then destroyed. Group runners for access control. Organization/enterprise-level runners shared across repos."},{"heading":"Runner Groups","text":"Organization runner groups: control which repos can use which runners. Enterprise runner groups: shared across organizations. Labels: tag runners with capabilities (gpu, high-mem, windows-gpu). Restrict by repo access."}],"interviewAnswer":"Self-hosted runners are runners you install and manage on your own infrastructure (on-premise or cloud VMs).","interviewQuestions":[{"question":"What is a self-hosted runner?","answer":"A runner you install on your own infrastructure instead of using GitHub-hosted runners."},{"question":"What is the security risk of self-hosted runners on public repos?","answer":"Anyone with repo access can execute code on your runner — only use with private repos or with strict controls."},{"question":"What is an ephemeral runner?","answer":"A runner that runs exactly one job and is destroyed afterward — ensuring a clean environment every time."},{"question":"Self-Hosted Runner — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Self-Hosted Runner — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Self-Hosted Runner — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Self-Hosted Runner — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Self-Hosted Runner — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Self-Hosted Runner — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Self-Hosted Runner — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Self-Hosted Runner</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Your Server</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Install runner agent</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitHub</text><text x=\"250\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Register & connect</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Execute Jobs</text><text x=\"420\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Run workflows</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Self-Hosted Runners: Your infrastructure, full con</text><text x=\"240\" y=\"122\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">trol. Security: use with private repos. Ephemeral </text><text x=\"240\" y=\"134\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">for isolation.</text></svg>","codeExamples":[{"title":"Runner Install","useCase":"Add self-hosted runner.","code":"# Download and configure\n./config.sh --url https://github.com/org/repo --token ABC123\n./run.sh","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the main security concern with self-hosted runners?","options":["Cost","Performance","Anyone with repo access can execute code on your infrastructure","Setup complexity"],"answer":2,"explanation":"Self-hosted runners on public repos allow anyone with repo access to run arbitrary code on your machine — significant security risk."},{"question":"Self-Hosted Runner — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Self-Hosted Runner — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Self-Hosted Runner — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Self-Hosted Runner — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Self-Hosted Runner — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Self-Hosted Runner — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Self-Hosted Runner — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Self-Hosted Runner — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Self-Hosted Runner — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-matrix"] = {"id":"github-actions-matrix","title":"Matrix Builds","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Matrix builds run the same job across multiple OS and version combinations simultaneously.","Defined via the strategy.matrix keyword. Creates combinations of specified variables.","Useful for: testing against multiple OS, language versions, dependency configurations.","Matrix Builds works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Matrix builds are like running the same test on multiple devices at once. Instead of writing separate jobs, you define a matrix and GitHub creates all combinations automatically.","deepDive":[{"heading":"Matrix Configuration","text":"strategy: matrix: os: [ubuntu-latest, windows-latest] node: [16, 18, 20]. Creates 6 jobs. Variables referenced as matrix.os and matrix.node. Combine with include and exclude."},{"heading":"Exclude and Include","text":"exclude removes specific combinations. include adds extra combinations. Use exclude to skip unsupported combos. Use include for special configurations."},{"heading":"Matrix Best Practices","text":"Maximize coverage. Minimize cost. Fail fast cancels remaining jobs on failure. Dynamic matrix from previous job."},{"heading":"Matrix Variables","text":"Predefined: matrix.os, matrix.node. Naming: any key name. max-parallel limits concurrent jobs."}],"interviewAnswer":"Matrix builds run the same job across multiple OS and version combinations simultaneously.","interviewQuestions":[{"question":"What is a matrix build?","answer":"Running the same job across multiple OS and version combinations in parallel."},{"question":"How to exclude a specific combination?","answer":"Use strategy.matrix.exclude."},{"question":"What does fail-fast do?","answer":"Cancels remaining matrix jobs when any job fails."},{"question":"Matrix Builds — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Matrix Builds — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Matrix Builds — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Matrix Builds — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Matrix Builds — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Matrix Builds — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Matrix Builds — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Matrix Builds</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OS: Ubuntu vs Node 16</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job 1</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OS: Ubuntu vs Node 18</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job 2</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OS: Windows vs Node 16</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job 3</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OS: Windows vs Node 18</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job 4</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Matrix Builds: NxM parallel jobs across OS and ver</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">sion combinations.</text></svg>","codeExamples":[{"title":"Matrix Configuration","useCase":"Multi-OS and Node version matrix.","code":"strategy:\n  matrix:\n    os: [ubuntu-latest, windows-latest]\n    node: [16, 18, 20]","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"How many jobs does a 2x3 matrix create?","options":["2","3","5","6"],"answer":3,"explanation":"A 2x3 matrix creates 6 jobs."},{"question":"Matrix Builds — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Matrix Builds — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Matrix Builds — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Matrix Builds — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Matrix Builds — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Matrix Builds — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Matrix Builds — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Matrix Builds — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Matrix Builds — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-marketplace"] = {"id":"github-actions-marketplace","title":"Actions Marketplace","difficulty":"beginner","estimatedMinutes":15,"tldr":["The GitHub Marketplace is a public directory of Actions shared by the community and verified publishers.","Actions can be: Docker container actions, JavaScript actions, or Composite actions.","Using an action: owner/repo@version (e.g., actions/checkout@v4). Always pin to a specific version.","Actions Marketplace works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"The Actions Marketplace is like an app store for your workflows. Need to deploy to AWS? There's an action for that. Send a Slack notification? There's an action for that. Run a Docker container? There's an action for that. You browse, find, and use them in your workflows.","deepDive":[{"heading":"Action Types","text":"Docker container: runs in a Docker container. Supports any language. Slower startup. JavaScript: runs directly on runner (fast). Node.js based. No container overhead. Composite: combines multiple steps into one action. Reusable across workflows."},{"heading":"Official Actions","text":"GitHub official: actions/checkout (checkout code), actions/setup-node (setup Node.js), actions/cache (dependency caching), actions/upload-artifact, actions/download-artifact. Third-party: AWS, Azure, Google Cloud, Docker, Slack, SonarQube."},{"heading":"Action Versions","text":"Pinning: actions/checkout@v4 (major version — recommended). @v4.2.0 (specific version). @main (branch — dangerous!). SHA: @a1b2c3d (commit SHA — most secure but not human-readable). Always pin to at least major version for stability."},{"heading":"Creating Actions","text":"Dockerfile action: Dockerfile in action repo. JavaScript action: action.yml + index.js. Composite action: action.yml with steps. Metadata: action.yml file with name, description, inputs, outputs. Publish to Marketplace."}],"interviewAnswer":"The GitHub Marketplace is a public directory of Actions shared by the community and verified publishers.","interviewQuestions":[{"question":"What are the three types of GitHub Actions?","answer":"Docker container, JavaScript, and Composite actions."},{"question":"How to reference an action from the Marketplace?","answer":"owner/repo@version — e.g., actions/checkout@v4."},{"question":"What is the recommended way to pin an action version?","answer":"Use major version tag (e.g., @v4) for automatic patch updates while avoiding breaking changes."},{"question":"Actions Marketplace — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Actions Marketplace — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Actions Marketplace — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Actions Marketplace — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Actions Marketplace — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Actions Marketplace — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Actions Marketplace — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Actions Marketplace</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Official</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">actions/* by GitHub</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Verified</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verified publishers</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Community</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Anyone can publish</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Custom</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Your own actions</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Actions Marketplace: Directory of reusable actions</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">. Types: Docker, JavaScript, Composite. Pin to @vX</text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> for stability.</text></svg>","codeExamples":[{"title":"Using Marketplace Actions","useCase":"Common actions in workflow.","code":"steps:\n  - uses: actions/checkout@v4\n  - uses: actions/setup-node@v4\n    with:\n      node-version: 20\n  - uses: actions/cache@v4\n    with:\n      path: ~/.npm\n      key: ${{ runner.os }}-node-${{ hashFiles('**/package-lock.json') }}","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the recommended way to reference an action?","options":["@main (branch)","@v4 (major version)","latest","no version"],"answer":1,"explanation":"Pinning to a major version tag (e.g., @v4) is recommended — it gets patch updates without breaking changes."},{"question":"Actions Marketplace — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Actions Marketplace — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Actions Marketplace — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Actions Marketplace — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Actions Marketplace — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Actions Marketplace — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Actions Marketplace — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Actions Marketplace — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Actions Marketplace — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-composite"] = {"id":"github-actions-composite","title":"Composite Actions","difficulty":"advanced","estimatedMinutes":20,"tldr":["Composite actions allow you to combine multiple workflow steps into a single reusable action.","Composite actions are defined in an action.yml file with a runs.using: \"composite\" section.","Composite actions can contain: run steps, uses steps (even other composite actions), inputs, outputs.","Composite Actions works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"A composite action is like creating a macro for your workflow. If you always do the same 5 steps (checkout, install, lint, test, build), you can bundle them into one reusable action. Then any workflow just uses my-actions/setup@v1 instead of repeating all 5 steps.","deepDive":[{"heading":"Composite Action Structure","text":"action.yml: name, description, inputs (optional), outputs (optional). runs: using: \"composite\" and steps: keyword. Steps are defined like workflow steps. Uses composite actions can use other actions. Inputs accessible via ${{ inputs.name }}. Outputs via ${{ steps.id.outputs.key }} and echo to $GITHUB_OUTPUT."},{"heading":"Composite vs Workflow","text":"Composite: called from within a job (one step). More flexible, can use inputs/outputs. Workflow: entire pipeline of jobs. Composite actions reduce duplication within a job. Reusable workflows orchestrate across jobs."},{"heading":"Best Practices","text":"Name composite actions descriptively. Document inputs and outputs. Version with tags. Use shell: bash explicitly in run steps. Keep focused — one responsibility. Test composite actions in isolation. Publish to Marketplace or use local path (./.github/actions/my-action)."}],"interviewAnswer":"Composite actions allow you to combine multiple workflow steps into a single reusable action.","interviewQuestions":[{"question":"What is a composite action?","answer":"An action that bundles multiple workflow steps into a single reusable unit."},{"question":"Where is a composite action defined?","answer":"In an action.yml file with runs.using: \"composite\" at the root or in .github/actions/."},{"question":"How to use a local composite action?","answer":"uses: ./.github/actions/my-action (relative path from repo root)."},{"question":"Composite Actions — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Composite Actions — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Composite Actions — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Composite Actions — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Composite Actions — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Composite Actions — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Composite Actions — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Composite Actions</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Workflow</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Calls composite action</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Composite Action</text><text x=\"250\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Bundled steps</text><rect x=\"180\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"250\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 1: Checkout</text><text x=\"250\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nested step</text><rect x=\"180\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"250\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 2: Install</text><text x=\"250\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nested step</text><text x=\"240\" y=\"150\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Composite Actions: Bundle multiple steps into one </text><text x=\"240\" y=\"162\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">reusable action. Defined in action.yml. Inputs/out</text><text x=\"240\" y=\"174\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">puts supported.</text></svg>","codeExamples":[{"title":"Composite action.yml","useCase":"Composite action definition.","code":"name: \"Setup Node App\"\ndescription: \"Checkout, install, lint\"\ninputs:\n  node-version:\n    required: true\n    default: \"20\"\nruns:\n  using: \"composite\"\n  steps:\n    - uses: actions/checkout@v4\n    - uses: actions/setup-node@v4\n      with:\n        node-version: ${{ inputs.node-version }}\n    - run: npm ci && npm run lint\n      shell: bash","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What keyword defines a composite action?","options":["runs.using: \"docker\"","runs.using: \"composite\"","type: composite","kind: composite"],"answer":1,"explanation":"Composite actions use runs.using: \"composite\" in action.yml."},{"question":"Composite Actions — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Composite Actions — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Composite Actions — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Composite Actions — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Composite Actions — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Composite Actions — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Composite Actions — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Composite Actions — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Composite Actions — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-reusable"] = {"id":"github-actions-reusable","title":"Reusable Workflows","difficulty":"advanced","estimatedMinutes":20,"tldr":["Reusable workflows allow you to call one workflow from another, avoiding duplication across repositories.","Called via the uses keyword in a job: uses: owner/repo/.github/workflows/workflow.yml@ref.","The called workflow must have on: workflow_call trigger. Inputs and secrets are passed explicitly.","Reusable Workflows works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Reusable workflows are like function calls for your CI/CD. Instead of copying the same CI workflow into every repo in your organization, you define it once and call it from each repo. Changes to the central workflow automatically apply everywhere.","deepDive":[{"heading":"Calling Workflow","text":"Caller job: uses: org/repo/.github/workflows/ci.yml@v1. Must specify with: for inputs and secrets: inherit or secrets: for secrets. Called workflow: on: workflow_call: inputs: (define inputs) secrets: (define secrets). Called workflow on any branch or tag."},{"heading":"Inputs & Secrets","text":"Inputs: on: workflow_call: inputs: name: description: required: type: string. Secrets: on: workflow_call: secrets: pass-to-secret: required: true. Pass: with: name: value and secrets: inherit or secrets: MY_SECRET."},{"heading":"Limitations","text":"Nested calls: max 4 levels deep. Secrets: must be explicitly declared in called workflow. Cannot call workflows from private repos in public repos (unless same owner). Matrix: cannot pass matrix strategy to called workflow (unfold matrix in caller)."},{"heading":"Use Cases","text":"Standard CI pipeline shared across all repos. Deployment workflow called with environment as input. Security scan workflow with shared configuration. Notification workflow for pipeline results."}],"interviewAnswer":"Reusable workflows allow you to call one workflow from another, avoiding duplication across repositories.","interviewQuestions":[{"question":"What are reusable workflows?","answer":"Workflows that can be called from other workflows using the workflow_call trigger."},{"question":"How to pass secrets to a reusable workflow?","answer":"Declare in called workflow\\'s on.workflow_call.secrets and pass with secrets: inherit or secrets: MY_SECRET."},{"question":"What is the nesting limit for reusable workflows?","answer":"A maximum of 4 levels of nested workflow calls."},{"question":"Reusable Workflows — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Reusable Workflows — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Reusable Workflows — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Reusable Workflows — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Reusable Workflows — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Reusable Workflows — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Reusable Workflows — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Reusable Workflows</text><rect x=\"10\" y=\"35\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"90\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Repo A Workflow</text><text x=\"90\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Calls shared CI</text><line x1=\"170\" y1=\"48\" x2=\"190\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"200\" y=\"35\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"280\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Shared CI Workflow</text><text x=\"280\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Defined once</text><rect x=\"200\" y=\"65\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"280\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Repo B Workflow</text><text x=\"280\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Calls shared CI</text><text x=\"240\" y=\"130\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Reusable Workflows: Call workflows from other repo</text><text x=\"240\" y=\"142\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">s. workflow_call trigger. Inputs and secrets passe</text><text x=\"240\" y=\"154\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">d explicitly.</text></svg>","codeExamples":[{"title":"Call Reusable Workflow","useCase":"Caller workflow.","code":"jobs:\n  ci:\n    uses: my-org/shared-workflows/.github/workflows/ci.yml@v1\n    with:\n      node-version: 20\n    secrets: inherit","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What trigger is required for reusable workflows?","options":["workflow_dispatch","workflow_call","workflow_run","repository_dispatch"],"answer":1,"explanation":"Reusable workflows must specify on: workflow_call to be callable from other workflows."},{"question":"Reusable Workflows — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Reusable Workflows — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Reusable Workflows — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Reusable Workflows — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Reusable Workflows — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Reusable Workflows — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Reusable Workflows — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Reusable Workflows — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Reusable Workflows — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-cache"] = {"id":"github-actions-cache","title":"Cache","difficulty":"intermediate","estimatedMinutes":15,"tldr":["The cache action stores and restores files between workflow runs, speeding up execution by avoiding re-downloads.","Common use cases: package manager caches (npm, pip, Maven, Gradle), Docker layers, build outputs.","Cache key determines when cache is invalidated. Use hash of lockfile for dependency cache.","Cache works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Cache is like a shortcut for your workflow. Instead of downloading all npm packages fresh every time you run a workflow, the cache saves them after the first run and restores them on subsequent runs — as long as your package.json hasn't changed.","deepDive":[{"heading":"Cache Action","text":"actions/cache@v4: path (what to cache), key (unique identifier), restore-keys (fallback). Cache hit: files restored (skips download). Cache miss: downloads and saves for next run. Cache size limit: 10GB per repository. Cache retention: 7 days since last access."},{"heading":"Cache Key Strategies","text":"Deps: key: ${{ runner.os }}-npm-${{ hashFiles(\\'**/package-lock.json\\') }}. OS-specific: include runner.os in key. Language-specific: npm vs pip vs Maven. Prefix: project-cache-${{ hash }}. Restore-keys: fallback to partial match (same prefix, different hash)."},{"heading":"Best Practices","text":"Cache lockfile-based dependencies only (deterministic). Include OS in key (different binaries per OS). Use restore-keys for partial cache hits. Separate caches for different dependency types. Monitor cache hit rate — low hit rate means cache isn\\'t working."},{"heading":"Cache Limits","text":"Max 10GB per repository. No limit per key. Cache eviction: LRU (least recently used) after 7 days. Multiple caches per job. Cross-branch cache access (same key)."}],"interviewAnswer":"The cache action stores and restores files between workflow runs, speeding up execution by avoiding re-downloads.","interviewQuestions":[{"question":"What does the cache action do?","answer":"Stores and restores files between workflow runs to speed up execution."},{"question":"What is the recommended cache key for npm?","answer":"key: ${{ runner.os }}-npm-${{ hashFiles(\\'**/package-lock.json\\') }}."},{"question":"How long does a cache entry persist?","answer":"7 days since last access (LRU eviction). Max 10GB per repository."},{"question":"Cache — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Cache — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Cache — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Cache — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Cache — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Cache — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Cache — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Cache</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">First Run</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache miss, download</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Save Cache</text><text x=\"250\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Store ~/.npm</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Next Run</text><text x=\"420\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache hit, restore</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Cache: Store dependencies between runs. actions/ca</text><text x=\"240\" y=\"122\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">che@v4. Key based on lockfile hash. 7-day retentio</text><text x=\"240\" y=\"134\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">n, 10GB limit.</text></svg>","codeExamples":[{"title":"Cache Setup","useCase":"Cache npm packages.","code":"- uses: actions/cache@v4\n  with:\n    path: ~/.npm\n    key: ${{ runner.os }}-npm-${{ hashFiles('**/package-lock.json') }}\n    restore-keys: |\n      ${{ runner.os }}-npm-","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What invalidates a cache entry?","options":["Time elapsed","Cache key changes","Number of runs","Runner type"],"answer":1,"explanation":"Cache is invalidated when the cache key changes — typically due to a modified lockfile."},{"question":"Cache — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Cache — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Cache — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Cache — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Cache — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Cache — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Cache — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Cache — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Cache — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-artifacts"] = {"id":"github-actions-artifacts","title":"Artifacts","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Artifacts are files produced during a workflow run that can be shared between jobs or downloaded after the run completes.","Actions: upload-artifact (save files), download-artifact (retrieve files).","Use cases: build outputs, test reports, coverage reports, logs, deployment packages.","Artifacts works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Artifacts are like handing off a package between workers on an assembly line. Job A builds the app and hands it off. Job B picks it up and runs tests on it. After the workflow finishes, you can download the package from the GitHub UI.","deepDive":[{"heading":"Upload Artifact","text":"actions/upload-artifact@v4: name (artifact name), path (files to upload), if-no-files-found (error/warn/ignore), retention-days (override default). Uploads: single files, directories, glob patterns (**/dist/**). Compression: automatically zipped (ZIP)."},{"heading":"Download Artifact","text":"actions/download-artifact@v4: name (specific artifact or all), path (destination), github-token (for cross-workflow). Download all: omit name. Download specific: use name. Merge: multiple uploads with same name merge into one."},{"heading":"Artifact Retention","text":"Default: 90 days (GitHub default). Per-artifact override: retention-days: 30. Reduce retention for temporary artifacts. Increase for compliance artifacts (audit logs, reports). PR artifacts: deleted when PR is closed."},{"heading":"Use Cases","text":"Build distribution: upload build artifacts, download in deploy job. Test reports: upload test results as HTML/JUnit, download for analysis. Coverage: upload coverage reports. Logs: upload debug logs for troubleshooting."}],"interviewAnswer":"Artifacts are files produced during a workflow run that can be shared between jobs or downloaded after the run completes.","interviewQuestions":[{"question":"What are GitHub Actions artifacts?","answer":"Files produced during workflow runs that can be shared between jobs or downloaded."},{"question":"How to upload build output to share between jobs?","answer":"actions/upload-artifact@v4 in build job, actions/download-artifact@v4 in dependent job."},{"question":"What is the default artifact retention period?","answer":"90 days. Can be overridden with retention-days."},{"question":"Artifacts — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Artifacts — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Artifacts — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Artifacts — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Artifacts — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Artifacts — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Artifacts — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Artifacts</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job A: Build</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm run build</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Upload</text><text x=\"250\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">dist/ folder</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job B: Deploy</text><text x=\"420\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Download & deploy</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Artifacts: Share files between jobs or download af</text><text x=\"240\" y=\"122\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ter run. upload-artifact/download-artifact. Retent</text><text x=\"240\" y=\"134\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ion: 90 days default.</text></svg>","codeExamples":[{"title":"Upload & Download","useCase":"Share artifacts between jobs.","code":"# Job build:\n- uses: actions/upload-artifact@v4\n  with:\n    name: build-output\n    path: dist/\n# Job deploy:\n- uses: actions/download-artifact@v4\n  with:\n    name: build-output","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What compression format do artifacts use?","options":["TAR.GZ","ZIP","RAR","No compression"],"answer":1,"explanation":"Artifacts are automatically compressed as ZIP files."},{"question":"Artifacts — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Artifacts — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Artifacts — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Artifacts — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Artifacts — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Artifacts — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Artifacts — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Artifacts — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Artifacts — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-secrets"] = {"id":"github-actions-secrets","title":"Secrets","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Secrets are encrypted environment variables that store sensitive information (API keys, tokens, passwords) for use in workflows.","Secrets are stored at repository, environment, or organization level. They are masked in workflow logs.","Reference: ${{ secrets.SECRET_NAME }}. Never hardcode secrets in workflow files.","Secrets works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Secrets are like locked safes for your passwords. You put the password in the safe (GitHub Secrets), and your workflow can open it and use it without ever showing the password. If someone reads the logs, the secret appears as ***.","deepDive":[{"heading":"Secret Levels","text":"Repository: Settings > Secrets and variables > Actions. Available to all workflows in repo. Environment: Settings > Environments > Environment > Secrets. Only available in jobs targeting that environment. Organization: Settings > Secrets. Available to selected repos."},{"heading":"Using Secrets","text":"Access: ${{ secrets.MY_SECRET }}. In actions: with: password: ${{ secrets.PASSWORD }}. In scripts: run: echo ${{ secrets.TOKEN }} | docker login. Masking: automatically hidden in logs (***). Can be used in: environment variables, action inputs, shell commands."},{"heading":"Best Practices","text":"Never use default values for secrets in workflows. Use environment-level secrets for environment-specific values. Rotate secrets regularly. Remove unused secrets. Use OpenID Connect (OIDC) instead of static secrets for cloud providers. Audit secret usage."},{"heading":"Limitations","text":"Max 100 secrets per repo. Secret size limit: 48KB. Secrets are not available in forked PRs (security). Use pull_request_target for forked PRs needing secrets. Not available in reusable workflows unless explicitly declared."}],"interviewAnswer":"Secrets are encrypted environment variables that store sensitive information (API keys, tokens, passwords) for use in workflows.","interviewQuestions":[{"question":"What are GitHub Actions secrets?","answer":"Encrypted environment variables for sensitive data (API keys, tokens) used in workflows."},{"question":"How are secrets protected in logs?","answer":"They are automatically masked — appearing as *** in log output."},{"question":"Are secrets available in workflows triggered from forks?","answer":"No — for security reasons, secrets are not passed to workflows triggered by forked repositories."},{"question":"Secrets — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Secrets — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Secrets — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Secrets — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Secrets — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Secrets — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Secrets — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Secrets</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Repository</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Repo-level secrets</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Environment</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per-environment</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Organization</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Org-wide secrets</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Workflow</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">${{ secrets.X }}</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Secrets: Encrypted sensitive values. Repository, e</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">nvironment, or organization level. Auto-masked in </text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">logs. Max 48KB.</text></svg>","codeExamples":[{"title":"Using Secrets","useCase":"Access secrets in workflows.","code":"steps:\n  - name: Login to Docker\n    run: echo ${{ secrets.DOCKER_PASSWORD }} | docker login -u ${{ secrets.DOCKER_USERNAME }} --password-stdin","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What environment provides secrets to workflows from forks?","options":["Secrets are NOT available from forks","push","pull_request_target","workflow_dispatch"],"answer":2,"explanation":"pull_request_target runs in the context of the base repo (has access to secrets) but is safer than pull_request for forked PRs."},{"question":"Secrets — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Secrets — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Secrets — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Secrets — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Secrets — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Secrets — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Secrets — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Secrets — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Secrets — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-variables"] = {"id":"github-actions-variables","title":"Variables","difficulty":"beginner","estimatedMinutes":10,"tldr":["Variables are non-sensitive configuration values that can be used across workflows.","Unlike secrets, variables are NOT encrypted and are visible in logs and UI.","Configuration levels: repository, environment, organization. Reference: ${{ vars.VARIABLE_NAME }}.","Variables works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Variables are like sticky notes with non-secret information for your workflow: \"Node version = 20\", \"Deploy Region = us-east-1\", \"Slack Channel = #deployments\". They are visible to anyone with repo access, so don't put passwords in them.","deepDive":[{"heading":"Variable Levels","text":"Repository: Settings > Secrets and variables > Actions > Variables. Environment: Environment settings > Variables. Organization: Organization settings > Secrets and variables. Organization variables can be limited to specific repos."},{"heading":"Using Variables","text":"Access: ${{ vars.NODE_VERSION }}. In run steps: run: node --version ${{ vars.NODE_VERSION }}. In with: node-version: ${{ vars.NODE_VERSION }}. Override precedence: environment > repository > organization."},{"heading":"Variables vs Secrets","text":"Variables: visible, non-sensitive (Node version, region, URLs). Secrets: encrypted, masked (API keys, passwords). Use variables for configuration, secrets for sensitive data. Both support the same levels and override order."}],"interviewAnswer":"Variables are non-sensitive configuration values that can be used across workflows.","interviewQuestions":[{"question":"What are GitHub Actions variables?","answer":"Non-sensitive configuration values available across workflows, visible in logs."},{"question":"What is the difference between vars and secrets?","answer":"Variables are visible and for non-sensitive config. Secrets are encrypted and masked for sensitive data."},{"question":"What is the variable precedence order?","answer":"Environment variables override repository variables, which override organization variables."},{"question":"Variables — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Variables — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Variables — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Variables — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Variables — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Variables — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Variables — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Variables</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Organization</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Org-wide vars</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Repository</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Repo vars</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Environment</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Env vars (highest)</text><text x=\"240\" y=\"140\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Variables: Non-sensitive config visible in logs. L</text><text x=\"240\" y=\"152\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">evels: org → repo → env. Reference: ${{ vars.NAME </text><text x=\"240\" y=\"164\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">}}.</text></svg>","codeExamples":[{"title":"Using Variables","useCase":"Access variables in workflow.","code":"env:\n  NODE_VERSION: ${{ vars.NODE_VERSION }}\nsteps:\n  - uses: actions/setup-node@v4\n    with:\n      node-version: ${{ env.NODE_VERSION }}","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"Can variables contain sensitive information?","options":["Yes, they are encrypted","No, they are visible in logs and UI","Only at org level","Only at env level"],"answer":1,"explanation":"Variables are NOT encrypted and are visible in logs. Use secrets for sensitive data."},{"question":"Variables — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Variables — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Variables — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Variables — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Variables — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Variables — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Variables — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Variables — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Variables — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-environments"] = {"id":"github-actions-environments","title":"Environments","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Environments in GitHub Actions represent deployment targets (dev, staging, production) with protection rules and configuration.","Each environment can have: required reviewers, wait timer, secrets, variables, and deployment branches.","Jobs target environments via the environment keyword. Deployments are tracked in the Environment dashboard.","Environments works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Environments are like secure rooms for your deployments. You can say: \"Only deploy to production after a manager approves. Only deploy from the main branch. Wait 10 minutes before going live.\" Environments track every deployment with a full history.","deepDive":[{"heading":"Environment Features","text":"Required reviewers: 1-6 people who must approve before deployment. Wait timer: time delay before environment accepts traffic. Deployment branches: restrict which branches can deploy. Environment secrets/vars: scoped to specific environments. Protection rules are enforced in deployment jobs."},{"heading":"Using Environments","text":"In job: environment: name: production. With URL: environment: name: production url: https://app.example.com. Deployment URL shown in GitHub UI. Environment variables: ${{{ vars.env_name.VAR }} syntax (or set in env context)."},{"heading":"Deployment History","text":"Active deployments: currently live. Inactive: previous deployments. Viewable in Environment tab. Each deployment linked to commit, workflow run, and reviewer. Track: who deployed, when, what commit, approval status."}],"interviewAnswer":"Environments in GitHub Actions represent deployment targets (dev, staging, production) with protection rules and configuration.","interviewQuestions":[{"question":"What are GitHub Environments?","answer":"Deployment targets with protection rules, secrets, and configuration (dev, staging, production)."},{"question":"What protection rules can environments have?","answer":"Required reviewers, wait timer, deployment branch restrictions."},{"question":"How to track deployment history?","answer":"Environments have a dashboard showing all deployments with commit, reviewer, and timestamp."},{"question":"Environments — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Environments — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Environments — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Environments — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Environments — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Environments — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Environments — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Environments</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dev</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No protections</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Staging</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Branch restriction</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Production</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Approval required</text><text x=\"240\" y=\"140\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Environments: Deployment targets with protection r</text><text x=\"240\" y=\"152\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ules. Required reviewers, wait timer, branch restr</text><text x=\"240\" y=\"164\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ictions. Full audit history.</text></svg>","codeExamples":[{"title":"Environment Job","useCase":"Target an environment in a job.","code":"deploy-prod:\n  runs-on: ubuntu-latest\n  environment:\n    name: production\n    url: https://app.example.com\n  steps:\n    - run: ./deploy.sh","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What protection rule can be added to production environment?","options":["Secrets","Required reviewers","Matrix strategy","Caching"],"answer":1,"explanation":"Required reviewers forces deployments to be approved by specified people before proceeding."},{"question":"Environments — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Environments — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Environments — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Environments — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Environments — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Environments — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Environments — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Environments — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Environments — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-deployment-protection"] = {"id":"github-actions-deployment-protection","title":"Deployment Protection Rules","difficulty":"advanced","estimatedMinutes":15,"tldr":["Deployment protection rules guard your environments, ensuring only authorized and safe deployments proceed.","Types: required reviewers, wait timer, branch protection, custom deployment gates (via GitHub Apps).","Rules are configured per-environment and enforced when a job references the environment.","Deployment Protection Rules works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Deployment protection rules are like security checkpoints for deploying code. Before code reaches production, it must pass through these checkpoints: a manager approves, the branch matches policy, and a mandatory wait timer elapses. This prevents rushed or unauthorized deployments.","deepDive":[{"heading":"Required Reviewers","text":"1-6 GitHub users/teams configured as approvers. When deployment job runs, it pauses and sends notification. Reviewer must approve via GitHub UI or API. Approvals expire after new commits pushed (if configured). Deployment proceeds only after all approvals."},{"heading":"Wait Timer","text":"Configured in seconds/minutes/hours. Pauses deployment after the approval step. Allows monitoring of previous deployment, manual rollback if needed, cache warmup, gradual rollout. Often combined with canary releases."},{"heading":"Deployment Branches","text":"Restrict which branches can deploy to an environment. Options: all branches, selected branches (list), protected branches only. Prevents: deploying feature branches to production, deploying unapproved changes."},{"heading":"Custom Protection Rules","text":"GitHub Apps can provide custom deployment gates. Examples: CI status check, load test results, security scan pass, compliance check, manual validation via external system. Apps approve/reject deployments via Deployment API."}],"interviewAnswer":"Deployment protection rules guard your environments, ensuring only authorized and safe deployments proceed.","interviewQuestions":[{"question":"What are deployment protection rules?","answer":"Gates that control and restrict deployments to environments (approvals, wait timer, branch restrictions)."},{"question":"What happens after a required reviewer approves?","answer":"Deployment proceeds (or continues after wait timer if configured)."},{"question":"What are custom protection rules?","answer":"Deployment gates provided by GitHub Apps — external validation like CI checks, load tests, compliance scans."},{"question":"Deployment Protection Rules — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Deployment Protection Rules — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Deployment Protection Rules — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Deployment Protection Rules — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Deployment Protection Rules — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Deployment Protection Rules — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Deployment Protection Rules — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Deployment Protection Rules</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job Triggers</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy to prod</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Required Reviewers</text><text x=\"250\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Approve?</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Wait Timer</text><text x=\"420\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Delay before deploy</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy!</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code goes live</text><text x=\"240\" y=\"120\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Deployment Protection: Required reviewers, wait ti</text><text x=\"240\" y=\"132\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">mer, branch restrictions, custom gates. Multiple l</text><text x=\"240\" y=\"144\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ayers of safety.</text></svg>","codeExamples":[{"title":"Protected Environment","useCase":"Environment with protection rules.","code":"environment:\n  name: production\n  url: https://app.com","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does a wait timer do in deployment protection?","options":["Blocks deployment permanently","Pauses deployment for a set time after approval","Speeds up deployment","Triggers rollback"],"answer":1,"explanation":"The wait timer creates a mandatory pause between approval and deployment, allowing monitoring or manual rollback."},{"question":"Deployment Protection Rules — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Deployment Protection Rules — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Deployment Protection Rules — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Deployment Protection Rules — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Deployment Protection Rules — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Deployment Protection Rules — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Deployment Protection Rules — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Deployment Protection Rules — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Deployment Protection Rules — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-scheduled"] = {"id":"github-actions-scheduled","title":"Scheduled Workflows","difficulty":"intermediate","estimatedMinutes":10,"tldr":["Scheduled workflows run at specified times using cron syntax, similar to cron jobs on Linux.","Configured via on: schedule: - cron: expression. Runs on the default branch (usually main).","Common uses: nightly builds, weekly dependency updates, daily report generation, cleanup tasks.","Scheduled Workflows works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":"Scheduled workflows are like setting an alarm clock for your automation. \"Run tests every night at 2 AM.\" \"Send a weekly report every Monday.\" \"Check for dependency updates every day.\" GitHub Actions uses standard cron syntax, the same as Linux cron jobs.","deepDive":[{"heading":"Cron Syntax","text":"Five fields: minute (0-59), hour (0-23), day of month (1-31), month (1-12), day of week (0-6, 0=Sunday). Examples: \"0 2 * * *\" (daily 2 AM). \"0 0 * * 1\" (weekly Monday midnight). \"*/15 * * * *\" (every 15 minutes). \"0 0 1 * *\" (monthly). Max frequency: every 5 minutes."},{"heading":"Schedule Behavior","text":"Runs on default branch (main). Only runs if workflow file exists on default branch. Uses UTC timezone. Delays possible if high system load. Consecutive runs: if previous run still active, new run may start or wait (configurable)."},{"heading":"Use Cases","text":"Nightly CI: full test suite + integration tests (too slow for per-commit). Dependency updates: check for outdated packages. Report generation: email daily reports, generate documentation. Data processing: ETL jobs, database maintenance. Cleanup: delete old artifacts, close stale issues."}],"interviewAnswer":"Scheduled workflows run at specified times using cron syntax, similar to cron jobs on Linux.","interviewQuestions":[{"question":"What is a scheduled workflow?","answer":"A workflow triggered by a cron schedule rather than a code event."},{"question":"What timezone does cron use in GitHub Actions?","answer":"UTC. Adjust your cron expression for your timezone."},{"question":"What is the minimum cron interval?","answer":"Every 5 minutes (e.g., */5 * * * *)."},{"question":"Scheduled Workflows — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Scheduled Workflows — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Scheduled Workflows — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Scheduled Workflows — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Scheduled Workflows — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Scheduled Workflows — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Scheduled Workflows — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Scheduled Workflows</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cron Trigger</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">\"0 2 * * *\"</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Workflow Runs</text><text x=\"250\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Daily at 2 AM UTC</text><text x=\"240\" y=\"100\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Scheduled Workflows: Cron-based triggers. on: sche</text><text x=\"240\" y=\"112\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">dule: - cron: expression. UTC timezone. Min interv</text><text x=\"240\" y=\"124\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">al: 5 min.</text></svg>","codeExamples":[{"title":"Scheduled Workflow","useCase":"Daily execution at 2 AM.","code":"name: Nightly CI\non:\n  schedule:\n    - cron: \"0 2 * * *\"\njobs:\n  test:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - run: npm ci && npm test","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What cron expression runs a workflow every Monday at 9 AM UTC?","options":["0 9 * * 1","0 9 1 * *","9 0 * * 1","0 0 * * 1"],"answer":0,"explanation":"\"0 9 * * 1\" — minute 0, hour 9, any day of month, any month, Monday (day 1)."},{"question":"Scheduled Workflows — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Scheduled Workflows — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Scheduled Workflows — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Scheduled Workflows — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Scheduled Workflows — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Scheduled Workflows — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Scheduled Workflows — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Scheduled Workflows — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Scheduled Workflows — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-conditional"] = {"id":"github-actions-conditional","title":"Conditional Execution","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Conditional execution controls whether jobs or steps run based on conditions evaluated at runtime.",["Conditions use the if keyword with expressions. Expressions are evaluated to true/false.","Common conditions: branch checks, event type, file changes, previous step status, secrets availability."],"Adopting Conditional Execution leads to faster deployments, lower failure rates, and quicker recovery when issues arise.","Conditional Execution works alongside other modern tools and platforms to support end-to-end software delivery processes."],"laymanDefinition":["Conditional execution is like adding \"if this, then do that\" logic to your workflow. \"Only deploy if we're on the main branch.\" \"Only run performance tests if the PR affects backend code.\" \"Only alert on failure.\" You control exactly when things happen."],"deepDive":[{"heading":"If Keyword","text":"Job level: job_name: if: condition. Step level: step: if: condition. If condition is true: job/step runs. If false: skipped (marked as \"skipped\" in UI). Functions: success(), failure(), always(), cancelled(). Combine: && (and), || (or), ! (not)."},{"heading":"Common Conditions","text":"Branch: github.ref == \\'refs/heads/main\\'. Event: github.event_name == \\'pull_request\\'. File changes: steps.changed-files.outputs.any_changed == \\'true\\'. Status: failure() (previous step failed). Secrets: github.repository_owner == \\'my-org\\'."},{"heading":"Status Check Functions","text":"success(): all previous steps succeeded (default). failure(): any previous step failed. always(): always run (regardless of status). cancelled(): workflow was cancelled. Combined: if: failure() && github.ref == \\'refs/heads/main\\'."},{"heading":"Expression Syntax","text":"${{ expression }}. Literals: strings (\\'hello\\'), numbers (42), booleans (true/false), null. Operators: ==, !=, <, >, &&, ||, !. Functions: contains(), startsWith(), endsWith(), format(), join(), toJSON(), fromJSON(), hashFiles()."}],"interviewAnswer":"Conditional execution controls whether jobs or steps run based on conditions evaluated at runtime.","interviewQuestions":[{"question":"What keyword controls conditional execution?","answer":"The if keyword at job or step level."},{"question":"What does failure() return?","answer":"true if any previous step in the job failed."},{"question":"How to always run a step regardless of previous failures?","answer":"Use if: always() — runs the step even if previous steps failed or the workflow was cancelled."},{"question":"Conditional Execution — How do you get started with this concept?","answer":"Getting started involves understanding the basics, setting up a proof of concept, and iterating."},{"question":"Conditional Execution — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Conditional Execution — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Conditional Execution — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Conditional Execution — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Conditional Execution — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Conditional Execution — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Conditional Execution</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push to main?</text><text x=\"80\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push to feature?</text><text x=\"80\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Skip deploy</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">PR opened?</text><text x=\"80\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Notify</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Schedule?</text><text x=\"80\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nightly tests</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Conditional Execution: if keyword with expressions</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">. Status functions: success(), failure(), always()</text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">, cancelled().</text></svg>","codeExamples":[{"title":"Conditional Steps","useCase":"Run steps conditionally.","code":"jobs:\n  deploy:\n    if: github.ref == 'refs/heads/main'\n    runs-on: ubuntu-latest\n    steps:\n      - run: ./deploy.sh\n      - name: Notify on failure\n        if: failure()\n        run: ./notify.sh","description":""},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What expression always evaluates to true?","options":["success()","failure()","always()","cancelled()"],"answer":2,"explanation":"always() returns true regardless of previous step status — use for cleanup tasks that must always run."},{"question":"Conditional Execution — What is the recommended approach?","options":["Start simple and iterate","Build everything at once","Skip testing","Avoid planning"],"answer":0,"explanation":"Starting simple and iterating is the most effective approach."},{"question":"Conditional Execution — What should be prioritized?","options":["Reliability and consistency","Speed only","Features over quality","Manual processes"],"answer":0,"explanation":"Reliability and consistency are foundational priorities."},{"question":"Conditional Execution — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Conditional Execution — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Conditional Execution — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Conditional Execution — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Conditional Execution — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Conditional Execution — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Conditional Execution — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["github-actions"]["github-actions-complete-cicd"] = {"id":"github-actions-complete-cicd","title":"Complete CI/CD Pipeline with GitHub Actions","difficulty":"advanced","estimatedMinutes":45,"tldr":["A complete CI/CD pipeline in GitHub Actions covers the full lifecycle: code commit, build, test, security scan, deploy, and monitor.","The pipeline uses matrix builds for cross-platform testing, caching for speed, secrets for security, and environments for deployment control.","Key stages: Checkout, Install dependencies, Lint, Unit tests, Integration tests, Security scan, Build, Upload artifacts, Deploy to staging, E2E tests, Deploy to production, Notify team.","Environment protection rules ensure deployments require approval for production. Artifacts pass build outputs between jobs.","The entire pipeline is defined in a single .github/workflows/ci-cd.yml file, making it version-controlled, reviewable, and reproducible."],"laymanDefinition":"A complete CI/CD pipeline with GitHub Actions is like an automated factory assembly line for your software. When a developer pushes code, the pipeline automatically: checks code quality, runs tests, builds the application, scans for security issues, deploys to staging for validation, and finally deploys to production with manual approval gates. Every step is visible, auditable, and automated.","deepDive":[{"heading":"Pipeline Architecture","text":"The pipeline is organized into sequential and parallel jobs connected by the needs keyword. Build and lint run in parallel first. Tests depend on build. Security scan runs in parallel with tests. Deploy to staging depends on tests passing. E2E tests validate the staging deployment. Production deploy awaits manual approval via environment protection rules. Artifacts share build outputs between jobs."},{"heading":"Stage 1: Quality & Build","text":"On every push and PR: Checkout code with actions/checkout@v4. Install dependencies with npm ci (fast, deterministic). Run linter with npm run lint. Run unit tests with npm test. Build the application. Upload build artifacts with actions/upload-artifact@v4. Cache node_modules with actions/cache@v4 for faster subsequent runs."},{"heading":"Stage 2: Testing & Security","text":"Integration tests run against real dependencies (service containers for databases). Security scanning with CodeQL or third-party actions. Dependency vulnerability check with npm audit or Dependabot. SAST (Static Application Security Testing) for code vulnerabilities. Secrets scanning to prevent credential leaks."},{"heading":"Stage 3: Deployment","text":"Staging deployment: automatic on successful tests. Uses environment with branch restriction (develop only). Smoke tests verify the deployment. E2E tests with Playwright or Cypress against staging URL. Production deployment: requires manual approval from designated reviewers via environment protection rules. Deployment URL shown in GitHub UI for easy access."},{"heading":"Monitoring & Notifications","text":"Slack/Discord/email notifications on pipeline status. Deployment status badges in README. GitHub Deployment dashboard tracks all deployments. Rollback trigger via workflow_dispatch with previous version. Alerts on failure with links to failing step logs."},{"heading":"CI/CD Workflow YAML","text":"The workflow file defines all jobs with their dependencies. Uses strategy matrix for Node.js versions 18 and 20 on ubuntu-latest. Environment production has required reviewers (2 people) and 10-minute wait timer. Secrets passed via GitHub Secrets for Docker registry, cloud credentials, and notification tokens."}],"interviewAnswer":"A complete CI/CD pipeline in GitHub Actions covers the full lifecycle: code commit, build, test, security scan, deploy, and monitor.","interviewQuestions":[{"question":"What are the main stages of a complete CI/CD pipeline?","answer":"Code quality (lint, unit tests), build, security scan, integration tests, deploy to staging, E2E tests, deploy to production, notify team."},{"question":"How are artifacts shared between jobs?","answer":"Use actions/upload-artifact in the build job and actions/download-artifact in dependent jobs. Artifacts persist across jobs in the same workflow run."},{"question":"What is the purpose of environment protection rules?","answer":"They enforce governance: required reviewers must approve production deployments, wait timer staggers traffic, and branch restriction limits which branches can deploy."},{"question":"How does the pipeline handle different Node.js versions?","answer":"Using strategy matrix: matrix.node [18, 20] runs the same job across both versions in parallel."},{"question":"What notifications does the pipeline send?","answer":"Slack/Discord messages on success, failure, and deployment status. Some teams also send email alerts for production failures."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Complete CI/CD Pipeline with GitHub Actions — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Complete CI/CD Pipeline with GitHub Actions</text><rect x=\"10\" y=\"20\" width=\"150\" height=\"22\" rx=\"5\" fill=\"#6f42c1\" stroke=\"#6f42c1\" stroke-width=\"1.5\"/><text x=\"85\" y=\"36\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push/PR Code</text><text x=\"85\" y=\"36\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Trigger event</text><line x1=\"160\" y1=\"31\" x2=\"175\" y2=\"31\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"185\" y=\"10\" width=\"140\" height=\"22\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"255\" y=\"26\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Quality</text><text x=\"255\" y=\"26\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Lint + Unit tests</text><rect x=\"185\" y=\"35\" width=\"140\" height=\"22\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"255\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"255\" y=\"51\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm ci + build</text><line x1=\"325\" y1=\"21\" x2=\"340\" y2=\"21\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"10\" width=\"140\" height=\"22\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"420\" y=\"26\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Security Scan</text><text x=\"420\" y=\"26\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">CodeQL + audit</text><line x1=\"325\" y1=\"46\" x2=\"340\" y2=\"46\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"185\" y=\"65\" width=\"140\" height=\"22\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"255\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Integration Tests</text><text x=\"255\" y=\"81\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Service containers</text><line x1=\"325\" y1=\"76\" x2=\"340\" y2=\"76\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"65\" width=\"140\" height=\"22\" rx=\"5\" fill=\"#20c997\" stroke=\"#20c997\" stroke-width=\"1.5\"/><text x=\"420\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy Staging</text><text x=\"420\" y=\"81\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto on success</text><line x1=\"490\" y1=\"76\" x2=\"505\" y2=\"76\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"185\" y=\"95\" width=\"160\" height=\"22\" rx=\"5\" fill=\"#fd7e14\" stroke=\"#fd7e14\" stroke-width=\"1.5\"/><text x=\"265\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">E2E Tests</text><text x=\"265\" y=\"111\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Playwright/Cypress</text><line x1=\"345\" y1=\"106\" x2=\"360\" y2=\"106\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"185\" y=\"125\" width=\"160\" height=\"22\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"265\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy Production</text><text x=\"265\" y=\"141\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Manual approval</text><line x1=\"345\" y1=\"136\" x2=\"360\" y2=\"136\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"185\" y=\"155\" width=\"160\" height=\"22\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"265\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Notify</text><text x=\"265\" y=\"171\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Slack/Email</text><text x=\"100\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Complete CI/CD Pipeline: Quality → Build → Test → </text><text x=\"100\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Security → Stage → E2E → Production → Notify. Ever</text><text x=\"100\" y=\"219\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">y step automated with governance gates.</text></svg>","codeExamples":[{"title":"Complete Workflow YAML","useCase":"Full CI/CD pipeline definition.","code":"name: Complete CI/CD Pipeline\n\non:\n  push:\n    branches: [main, develop]\n  pull_request:\n    branches: [main]\n\nenv:\n  NODE_VERSION: \"20\"\n\njobs:\n  quality:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with:\n          node-version: ${{ env.NODE_VERSION }}\n      - uses: actions/cache@v4\n        with:\n          path: ~/.npm\n          key: ${{ runner.os }}-npm-${{ hashFiles(\"**/package-lock.json\") }}\n      - run: npm ci\n      - run: npm run lint\n      - run: npm test\n\n  security:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - name: Initialize CodeQL\n        uses: github/codeql-action/init@v3\n      - name: Perform CodeQL Analysis\n        uses: github/codeql-action/analyze@v3\n\n  build:\n    runs-on: ubuntu-latest\n    needs: [quality]\n    steps:\n      - uses: actions/checkout@v4\n      - run: npm ci\n      - run: npm run build\n      - uses: actions/upload-artifact@v4\n        with:\n          name: build-output\n          path: dist/\n\n  test-e2e:\n    runs-on: ubuntu-latest\n    needs: [build]\n    services:\n      postgres:\n        image: postgres:16\n        env:\n          POSTGRES_PASSWORD: test\n    steps:\n      - uses: actions/checkout@v4\n      - run: npm ci\n      - run: npm run test:e2e\n\n  deploy-staging:\n    runs-on: ubuntu-latest\n    needs: [build, security, test-e2e]\n    if: github.ref == \"refs/heads/develop\"\n    environment:\n      name: staging\n      url: https://staging.example.com\n    steps:\n      - uses: actions/download-artifact@v4\n        with:\n          name: build-output\n      - run: ./deploy.sh staging\n\n  deploy-production:\n    runs-on: ubuntu-latest\n    needs: [deploy-staging]\n    if: github.ref == \"refs/heads/main\"\n    environment:\n      name: production\n      url: https://app.example.com\n    steps:\n      - uses: actions/download-artifact@v4\n        with:\n          name: build-output\n      - run: ./deploy.sh production\n\n  notify:\n    runs-on: ubuntu-latest\n    needs: [deploy-production, deploy-staging]\n    if: always()\n    steps:\n      - name: Slack Notification\n        run: |\n          if [ \"${{ job.status }}\" = \"success\" ]; then\n            echo \"Deployment succeeded\"\n          else\n            echo \"Deployment failed\"\n          fi","description":"Complete CI/CD workflow demonstrating all stages from code push to production deployment with security scanning and notifications."},{"title":"Common Use Case","useCase":"Typical implementation","code":"# Common implementation pattern\n# Used in everyday scenarios","description":"Standard use case example."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the purpose of the needs keyword in jobs?","options":["Runs all jobs in parallel","Defines job dependencies and execution order","Skips jobs randomly","Duplicates jobs"],"answer":1,"explanation":"The needs keyword creates a dependency graph — a job only runs after all its specified dependencies complete successfully. This defines the pipeline execution order."},{"question":"What is the benefit of using environment protection rules for production?","options":["Faster deployments","Required approvals prevent unauthorized deployments","Reduces server costs","Increases test coverage"],"answer":1,"explanation":"Environment protection rules ensure governance: required reviewers must approve, which prevents accidental or unauthorized production deployments."},{"question":"What does the services keyword provide in a job?","options":["Installs system packages","Runs service containers (like databases) for testing","Deploys to cloud","Manages secrets"],"answer":1,"explanation":"The services keyword runs Docker containers alongside the job, commonly used for databases (PostgreSQL, MySQL) needed during integration tests."},{"question":"What is the purpose of actions/upload-artifact?","options":["Cache dependencies","Share build outputs between jobs","Deploy to production","Run tests"],"answer":1,"explanation":"upload-artifact saves files (like build output) that can be downloaded in subsequent jobs using download-artifact, enabling cross-job data sharing."},{"question":"What happens when a job uses if: always()?","options":["Runs only on success","Runs regardless of previous job statuses","Never runs","Runs only on failure"],"answer":1,"explanation":"if: always() ensures a job runs no matter what — useful for cleanup and notification steps that must execute even after failures."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Complete CI/CD Pipeline with GitHub Actions — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};